	NODE(int x,int y,int c,int num) : x(x) , y(y) , c(c) , num(num) {}

};

int W,H;



int doit(vector<NODE> v){

	queue<NODE> Q;

	for(int i = 0 ; i < v.size() ; i++){

		Q.push(NODE(v[i].x,v[i].y,0,i));

	}

	int cnt[100][100]={};

	int ans[100][100];

	for(int i = 0 ; i < 100 ; i++)

		for(int j = 0 ; j < 100 ; j++)

